Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateClient(HttpStatusCode status, string content = "")
    {
        var handler = new FakeHandler(new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        });
        return new HttpClient(handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.OK, "hello"));

        // Act
        var result = await fetcher.FetchAsync("http://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.NotFound));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("http://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange - handler that delays so cancellation can fire
        var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act - cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal fake handler for testability
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---------|-----|
| Sealed class | `public sealed class` for performance |
| Constructor-injected TestContext | Enables `_testContext.CancellationToken` |
| `[Timeout]` | Fails test if it hangs; triggers `CancellationToken` |
| `TestContext.CancellationToken` | Propagated into async calls — respects `[Timeout]` |
| `Assert.ThrowsExactlyAsync` | Modern exception assertion (replaces `[ExpectedException]`) |
| Cancellation testing | Verifies the method honors the token |

The `[Timeout]` attribute automatically cancels `TestContext.CancellationToken` when time expires, so always pass it through to your async code under test.
